import React, { useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/solid";

// 1. Moved sub-components OUTSIDE the main component to prevent re-mounting/lost focus.
const FloatingLabelInput = ({ name, type = "text", label, value, onChange }) => (
  <div className="relative w-full">
    <input
      type={type}
      name={name}
      id={name}
      value={value}
      onChange={onChange}
      placeholder=" " /* 2. Added empty placeholder required by Tailwind's peer-placeholder-shown */
      className="peer w-full px-4 py-3 sm:py-4 rounded-lg border border-gray-400 text-black placeholder-transparent focus:outline-none focus:ring-2 focus:ring-purple-400"
    />
    <label
      htmlFor={name}
      className="absolute left-4 top-3 text-gray-500 text-base transition-all
                peer-placeholder-shown:top-3.5 peer-placeholder-shown:text-base peer-placeholder-shown:text-gray-400
                peer-focus:top-0 peer-focus:text-sm peer-focus:text-purple-500"
    >
      {label}
    </label>
  </div>
);

const FloatingLabelSelect = ({ name, label, options, value, onChange }) => (
  <div className="relative w-full mt-2">
    <select
      name={name}
      id={name}
      value={value}
      onChange={onChange}
      className="peer w-full px-4 py-3 sm:py-4 rounded-lg border border-gray-400 text-black bg-white/30 focus:outline-none focus:ring-2 focus:ring-purple-400 appearance-none"
    >
      {options.map((opt) => (
        <option key={opt.value} value={opt.value}>
          {opt.label}
        </option>
      ))}
    </select>
    <label
      htmlFor={name}
      className="absolute left-4 -top-2.5 bg-white px-1 text-gray-500 text-sm rounded-md"
    >
      {label}
    </label>
  </div>
);

const DueDateInput = ({ value, onChange }) => (
  <div className="relative w-full">
    <input
      type="date"
      name="dueDate"
      id="dueDate"
      value={value}
      onChange={onChange}
      placeholder=" " 
      className="peer w-full px-4 pt-6 pb-2 rounded-lg border border-gray-400 text-black placeholder-transparent focus:outline-none"
    />
    <label
      htmlFor="dueDate"
      className="absolute left-4 top-4 text-gray-400 text-base transition-all
                peer-placeholder-shown:top-6 peer-placeholder-shown:text-gray-400 peer-placeholder-shown:text-base
                peer-focus:top-0 peer-focus:text-sm peer-focus:text-purple-500"
    >
      Due Date
    </label>
  </div>
);

// Main Component
export default function AddTask({ closeModal, onTaskAdded }) {
  const [formData, setFormData] = useState({
    title: "",
    dueDate: "",
    priority: "MEDIUM",
    category: "",
    completed: false,
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loadingAI, setLoadingAI] = useState(false);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === "checkbox" ? checked : value,
    });
  };

  const handleAIGenerate = async () => {
    setLoadingAI(true);
    setError("");

    try {
      const res = await fetch("http://localhost:8086/tasks/ai-generate", {
        method: "POST",
      });
      const data = await res.json();
      setFormData({
        ...formData,
        title: data.title || "",
        dueDate: data.dueDate || "",
        priority: data.priority || "MEDIUM",
        category: data.category || "",
      });
    } catch (err) {
      setError("AI generation failed");
    } finally {
      setLoadingAI(false);
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!formData.title || !formData.dueDate) {
      setError("Please fill required fields");
      return;
    }

    try {
      const res = await fetch("http://localhost:8086/tasks", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...formData,
          autoGenerated: false,
          suggestionSource: "AI",
          notified: false,
        }),
      });

      if (res.ok) {
        setSuccess("Task added successfully!");
        if (onTaskAdded) onTaskAdded();
        setTimeout(() => closeModal(), 1000);
      } else {
        setError("Server error");
      }
    } catch (err) {
      setError("Server error");
    }
  };

  return (
    <div className="w-full max-w-md sm:w-[420px] p-6 sm:p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl relative">
      <button
        onClick={closeModal}
        className="absolute top-3 right-3 text-white hover:text-gray-200 transition-colors"
      >
        <XMarkIcon className="w-6 h-6" />
      </button>

      <h2 className="text-2xl font-bold text-white text-center mb-4">
        Add Task
      </h2>

      <button
        type="button"
        onClick={handleAIGenerate}
        disabled={loadingAI}
        className="w-full mb-4 py-2 rounded-lg bg-purple-500/70 hover:bg-purple-600 disabled:bg-purple-400 text-white font-semibold transition"
      >
        {loadingAI ? "Analyzing..." : "🤖 Generate Task"}
      </button>

      {success && <p className="text-green-300 text-center mb-2">{success}</p>}
      {error && <p className="text-red-300 text-center mb-2">{error}</p>}

      <form onSubmit={handleAdd} className="space-y-4 mt-2">
        <FloatingLabelInput 
          name="title" 
          label="Task Title" 
          value={formData.title} 
          onChange={handleChange} 
        />

        <DueDateInput 
          value={formData.dueDate} 
          onChange={handleChange} 
        />

        <FloatingLabelSelect
          name="priority"
          label="Priority"
          value={formData.priority}
          onChange={handleChange}
          options={[
            { value: "LOW", label: "Low" },
            { value: "MEDIUM", label: "Medium" },
            { value: "HIGH", label: "High" },
          ]}
        />

        <FloatingLabelInput 
          name="category" 
          label="Category" 
          value={formData.category} 
          onChange={handleChange} 
        />

        <button
          type="submit"
          className="w-full py-2 mt-4 rounded-lg bg-white/30 hover:bg-white/40 text-black font-semibold transition-colors"
        >
          Add Task
        </button>
      </form>
    </div>
  );
}
